    private void mLLenarComboEmpresa() {
        this.xlleno = false;
        this.JCBEmpresa.removeAllItems();
        if (this.xtipo == 0) {
            this.xsql = "SELECT  `f_empresacontxconvenio`.`Id` , `f_empresacontxconvenio`.`Nbre` , `f_empresacontxconvenio`.`Nbre` , `f_empresacontxconvenio`.`EsCapitado` FROM `f_factura_capita` INNER JOIN  `f_liquidacion`  ON (`f_factura_capita`.`Id_Liquidacion` = `f_liquidacion`.`Id`) INNER JOIN `ingreso`  ON (`ingreso`.`Id` = `f_liquidacion`.`Id_Ingreso`) INNER JOIN `f_empresacontxconvenio`  ON (`ingreso`.`Id_EmpresaContxConv` = `f_empresacontxconvenio`.`Id`) WHERE (`f_factura_capita`.EstaArmada IN (" + this.armada.toString().replaceAll("[\\[\\]]", "") + ")  AND  `f_factura_capita`.`Fecha_FacturaCapita` >='" + this.xmt.formatoAMD.format(this.txtFechaIni.getDate()) + "' AND `f_factura_capita`.`Fecha_FacturaCapita` <='" + this.xmt.formatoAMD.format(this.txtFechaFin.getDate()) + "') GROUP BY `f_empresacontxconvenio`.`Id` ORDER BY `f_empresacontxconvenio`.`Nbre` ASC ";
        } else {
            this.xsql = "SELECT  `f_empresacontxconvenio`.`Id` , `f_empresacontxconvenio`.`Nbre` , `f_empresacontxconvenio`.`Nbre` , `f_empresacontxconvenio`.`EsCapitado` FROM `ingreso` INNER JOIN  `f_liquidacion`  ON (`ingreso`.`Id` = `f_liquidacion`.`Id_Ingreso`) INNER JOIN  `f_empresacontxconvenio`  ON (`ingreso`.`Id_EmpresaContxConv` = `f_empresacontxconvenio`.`Id`) INNER JOIN  `f_factura_evento`  ON (`f_factura_evento`.`Id_Liquidacion` = `f_liquidacion`.`Id`) WHERE (`f_factura_evento`.EstaArmada IN (" + this.armada.toString().replaceAll("[\\[\\]]", "") + ") AND  `f_factura_evento`.`Fecha_FacturaEvento` >='" + this.xmt.formatoAMD.format(this.txtFechaIni.getDate()) + "' AND `f_factura_evento`.`Fecha_FacturaEvento` <='" + this.xmt.formatoAMD.format(this.txtFechaFin.getDate()) + "') GROUP BY `f_empresacontxconvenio`.`Id` ORDER BY `f_empresacontxconvenio`.`Nbre` ASC ";
        }
        System.out.println("empresa : " + this.xsql);
        this.xidempresa = this.xct.llenarComboyLista(this.xsql, this.xidempresa, this.JCBEmpresa, 4);
        if (this.xidempresa.length > 1) {
            this.JCBEmpresa.setSelectedIndex(-1);
        } else if (this.xidempresa.length == 1) {
            this.JCBEmpresa.setSelectedIndex(0);
            this.idConvenio = this.xidempresa[this.JCBEmpresa.getSelectedIndex()][0];
        }
        this.xct.cerrarConexionBd();
        this.xlleno = true;
    }

